import React, { useState, useEffect } from "react";

// Screens
import SplashScreen from "./screens/SplashScreen.jsx";
import SignInScreen from "./screens/SignInScreen.jsx";
import SignUpScreen from "./screens/SignUpScreen.jsx";
import HomeScreen from "./screens/HomeScreen.jsx";
import GoalsScreen from "./screens/GoalsScreen.jsx";
import LoansScreen from "./screens/LoansScreen.jsx";
import ProfileScreen from "./screens/ProfileScreen.jsx";
import TransactionHistoryScreen from "./screens/TransactionHistoryScreen.jsx";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen.jsx";
import DepositScreen from "./screens/DepositScreen.jsx";
import WithdrawScreen from "./screens/WithdrawScreen.jsx";
import SavingsDepositScreen from "./screens/SavingsDepositScreen.jsx";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawScreen.jsx";

// Icons
import { Home, Target, CreditCard, User } from "lucide-react";

// Toast component for notifications
function Toast({ message, type }) {
  return (
    <div
      className={`fixed top-6 left-1/2 transform -translate-x-1/2 px-6 py-3 rounded-xl text-white font-medium z-50 shadow-md ${
        type === "success" ? "bg-emerald-600" : "bg-red-600"
      }`}
    >
      {message}
    </div>
  );
}

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Splash");
  const [tab, setTab] = useState("Home");

  // Mock user & data
  const [user] = useState({
    name: "Faith Bode",
    email: "faith@example.com",
    joinedDate: "Jan 2025",
  });

  const [balance, setBalance] = useState(1500);
  const [savingsBalance, setSavingsBalance] = useState(300);

  const [goals] = useState([
    { id: 1, title: "Buy PS5", description: "Save for PS5 console", amountSaved: 100, targetAmount: 500 },
  ]);

  const [loans] = useState([]);

  const [transactions, setTransactions] = useState([]);

  // Toast state
  const [toast, setToast] = useState(null);

  const showToast = (message, type = "success") => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 2500);
  };

  // Splash → SignIn
  useEffect(() => {
    const timer = setTimeout(() => setCurrentScreen("SignIn"), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Transaction handlers
  const handleDeposit = (amount) => {
    setBalance((prev) => prev + amount);
    const t = { id: Date.now(), type: "deposit", title: "Deposit", amount, date: new Date().toLocaleDateString() };
    setTransactions((prev) => [t, ...prev]);
    setCurrentScreen("Dashboard");
    showToast(`Successfully deposited $${amount}`);
  };

  const handleWithdraw = (amount) => {
    if (amount > balance) {
      showToast("Insufficient balance", "error");
      return;
    }
    setBalance((prev) => prev - amount);
    const t = { id: Date.now(), type: "withdraw", title: "Withdrawal", amount, date: new Date().toLocaleDateString() };
    setTransactions((prev) => [t, ...prev]);
    setCurrentScreen("Dashboard");
    showToast(`Successfully withdrew $${amount}`);
  };

  const handleSavingsDeposit = (amount) => {
    if (amount > balance) {
      showToast("Insufficient main balance", "error");
      return;
    }
    setBalance((prev) => prev - amount);
    setSavingsBalance((prev) => prev + amount);
    const t = { id: Date.now(), type: "savings", title: "Savings Deposit", amount, date: new Date().toLocaleDateString() };
    setTransactions((prev) => [t, ...prev]);
    setCurrentScreen("Dashboard");
    showToast(`Deposited $${amount} to savings`);
  };

  const handleSavingsWithdraw = (amount) => {
    if (amount > savingsBalance) {
      showToast("Insufficient savings balance", "error");
      return;
    }
    setSavingsBalance((prev) => prev - amount);
    setBalance((prev) => prev + amount);
    const t = { id: Date.now(), type: "savingsWithdraw", title: "Savings Withdrawal", amount, date: new Date().toLocaleDateString() };
    setTransactions((prev) => [t, ...prev]);
    setCurrentScreen("Dashboard");
    showToast(`Withdrew $${amount} from savings`);
  };

  // Render screens
  const renderScreen = () => {
    switch (currentScreen) {
      case "Splash":
        return <SplashScreen onFinish={() => setCurrentScreen("SignIn")} />;

      case "SignIn":
        return <SignInScreen onSignIn={() => setCurrentScreen("Dashboard")} />;

      case "SignUp":
        return <SignUpScreen onSignUp={() => setCurrentScreen("Dashboard")} />;

      case "Deposit":
        return <DepositScreen onDeposit={handleDeposit} goBack={() => setCurrentScreen("Dashboard")} />;

      case "Withdraw":
        return <WithdrawScreen balance={balance} onWithdraw={handleWithdraw} goBack={() => setCurrentScreen("Dashboard")} />;

      case "SavingsDeposit":
        return <SavingsDepositScreen savingsBalance={savingsBalance} onDeposit={handleSavingsDeposit} goBack={() => setCurrentScreen("Dashboard")} />;

      case "SavingsWithdraw":
        return <SavingsWithdrawScreen savingsBalance={savingsBalance} onWithdraw={handleSavingsWithdraw} goBack={() => setCurrentScreen("Dashboard")} />;

      case "Transactions":
        return <TransactionHistoryScreen transactions={transactions} />;

      case "TransactionReceipt":
        const latestTransaction = transactions[0] || null;
        return <TransactionReceiptScreen transaction={latestTransaction} goBack={() => setCurrentScreen("Transactions")} />;

      case "Dashboard":
      default:
        switch (tab) {
          case "Home":
            return <HomeScreen balance={balance} savingsBalance={savingsBalance} transactions={transactions} userName={user.name} openScreen={setCurrentScreen} />;
          case "Goals":
            return <GoalsScreen goals={goals} />;
          case "Loans":
            return <LoansScreen loans={loans} />;
          case "Profile":
            return <ProfileScreen user={user} />;
          default:
            return <HomeScreen balance={balance} savingsBalance={savingsBalance} transactions={transactions} userName={user.name} openScreen={setCurrentScreen} />;
        }
    }
  };

  const tabs = [
    { key: "Home", label: "Home", icon: Home },
    { key: "Goals", label: "Goals", icon: Target },
    { key: "Loans", label: "Loans", icon: CreditCard },
    { key: "Profile", label: "Profile", icon: User },
  ];

  return (
    <div className="min-h-screen bg-gray-50 pb-24 relative">
      {renderScreen()}

      {currentScreen === "Dashboard" && (
        <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-gray-200 flex">
          {tabs.map((t) => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={`flex-1 py-3 flex flex-col items-center ${
                tab === t.key ? "text-teal-600 font-bold" : "text-gray-400"
              }`}
            >
              <t.icon size={22} />
              <span className="text-xs mt-1">{t.label}</span>
            </button>
          ))}
        </nav>
      )}

      {toast && <Toast message={toast.message} type={toast.type} />}
    </div>
  );
}
